"use strict";(self.webpackChunkmbse_blog=self.webpackChunkmbse_blog||[]).push([[2030],{718:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>o,default:()=>c,frontMatter:()=>s,metadata:()=>a,toc:()=>d});var a=n(3068),i=n(4848),r=n(8453);const s={title:"Requirement Management Tool - Why Automotive and IoT Teams Can't Afford to Skip One",description:"Discover why a requirement management tool is critical for automotive and ODM IoT teams, the failures it prevents, and an overview of Codebeamer, ReqView, and ODM Trace.",slug:"requirement-management-tool-automotive-iot",authors:["blagoje"],tags:["MBSE","automotive","EV","systems engineering","requirements management"],image:"./image1.png"},o=void 0,l={image:n(9652).A,authorsImageUrls:[void 0]},d=[{value:"Why Requirement Management Tools Matter",id:"why-requirement-management-tools-matter",level:2},{value:"The Failures Requirement Management Tools Actually Prevent",id:"the-failures-requirement-management-tools-actually-prevent",level:2},{value:"Automotive vs. ODM IoT: A Parallel in Complexity, Not in Need",id:"automotive-vs-odm-iot-a-parallel-in-complexity-not-in-need",level:2},{value:"Tool Overview: Codebeamer",id:"tool-overview-codebeamer",level:2},{value:"Tool Overview: ReqView",id:"tool-overview-reqview",level:2},{value:"The Gap in the Middle \u2014 and Why I&#39;m Building ODM Trace",id:"the-gap-in-the-middle--and-why-im-building-odm-trace",level:2},{value:"Choosing the Right Tool for Where You Are",id:"choosing-the-right-tool-for-where-you-are",level:2}];function h(e){const t={a:"a",em:"em",h2:"h2",img:"img",li:"li",p:"p",strong:"strong",ul:"ul",...(0,r.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.img,{alt:"ODM trace",src:n(2587).A+"",width:"1321",height:"564"}),"\nRequirement Management Tool - Why Automotive and IoT Teams Can't Afford to Skip One"]}),"\n",(0,i.jsxs)(t.p,{children:["Welcome back to ",(0,i.jsx)(t.strong,{children:"MBSE Explained"}),"! If you've spent any time in automotive or embedded systems development, you've probably heard the phrase \"the requirement wasn't clear\" right before a project blew its budget or missed a milestone. That sentence is usually the tip of a much bigger iceberg."]}),"\n",(0,i.jsxs)(t.p,{children:["In this post, I want to talk about something less glamorous than SysML diagrams or digital twins, but arguably more foundational: the ",(0,i.jsx)(t.strong,{children:"requirement management tool"}),". Having spent nearly five years as a Model-Based Embedded Software Developer and Architect, followed by a year and a half working as a Model-Based Systems Architect on automotive programs, I've seen firsthand what happens when requirements live in scattered spreadsheets versus when they live in a proper, traceable system."]}),"\n",(0,i.jsxs)(t.p,{children:["We'll look at why requirement management (RM) tools matter, the specific failures they prevent, how the same principles apply \u2014 at a smaller scale \u2014 to ODM IoT hardware projects, and I'll walk through two established tools, ",(0,i.jsx)(t.strong,{children:"Codebeamer"})," and ",(0,i.jsx)(t.strong,{children:"ReqView"}),". I'll also introduce a tool I'm building myself, ",(0,i.jsx)(t.strong,{children:"ODM Trace"}),', aimed at teams that fall in the gap between "spreadsheet chaos" and "full automotive-grade ALM."']}),"\n",(0,i.jsx)(t.h2,{id:"why-requirement-management-tools-matter",children:"Why Requirement Management Tools Matter"}),"\n",(0,i.jsx)(t.p,{children:"In any complex product \u2014 a battery management system, a powertrain controller, a converter unit \u2014 requirements are the contract between what stakeholders need and what engineers build. When that contract lives in disconnected Word documents, emails, and Excel tabs, it stops being a contract. It becomes a rumor."}),"\n",(0,i.jsx)(t.p,{children:"A dedicated RM tool exists to keep that contract enforceable:"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Single source of truth"})," \u2014 everyone works from the same, versioned requirement, not five copies with different edit dates."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Traceability"})," \u2014 every requirement links forward to design and test, and backward to its origin (customer need, standard, stakeholder ask)."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Change impact analysis"})," \u2014 when a requirement changes, you immediately see what design elements, tests, and risks are affected."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Audit readiness"})," \u2014 for regulated domains, you need a defensible history of who approved what, and when."]}),"\n"]}),"\n",(0,i.jsxs)(t.p,{children:["None of this is optional once a project passes a certain complexity threshold. The question isn't ",(0,i.jsx)(t.em,{children:"whether"})," you need traceability \u2014 it's whether you're going to get it from a purpose-built tool, or the hard way, during a failed audit."]}),"\n",(0,i.jsx)(t.h2,{id:"the-failures-requirement-management-tools-actually-prevent",children:"The Failures Requirement Management Tools Actually Prevent"}),"\n",(0,i.jsx)(t.p,{children:"It's easy to treat RM tooling as bureaucratic overhead \u2014 until you've lived through the alternative. Here are the failure modes I've personally seen an RM tool prevent (or, in their absence, cause real damage):"}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Silent requirement drift."}),' A requirement gets "clarified" in a hallway conversation or a Slack message, the spreadsheet never gets updated, and three teams downstream build against the old version. Nobody notices until integration testing.']}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Untraceable late-stage defects."}),' A defect surfaces during validation, but nobody can quickly answer "which requirement does this violate, and who approved it?" Without traceability, root-causing turns into an archaeology dig instead of a five-minute query.']}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Orphaned requirements."})," Requirements get written, but never linked to a test case or a design element. They sit there unverified until an assessor \u2014 or worse, a field failure \u2014 finds them."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Duplicate or conflicting requirements."}),' Two teams write slightly different versions of "the same" requirement in two different documents. Nobody reconciles them until implementation reveals the conflict.']}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Compliance gaps that surface at the worst possible time."})," In automotive, standards like ",(0,i.jsx)(t.strong,{children:"ISO 26262"})," expect demonstrable bidirectional traceability from safety goals down to verification. Discovering a gap during a functional safety assessment \u2014 instead of during development \u2014 is expensive and, in the worst case, program-threatening."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Change requests with no visible blast radius."})," A last-minute change to a converter system's requirement ripples into hardware, firmware, and test plans, but without linked traceability, someone finds out about the ripple only after it breaks something."]}),"\n",(0,i.jsxs)(t.p,{children:["An RM tool doesn't eliminate human error. What it does is make the error ",(0,i.jsx)(t.em,{children:"visible early"}),", instead of letting it hide until it's expensive."]}),"\n",(0,i.jsx)(t.h2,{id:"automotive-vs-odm-iot-a-parallel-in-complexity-not-in-need",children:"Automotive vs. ODM IoT: A Parallel in Complexity, Not in Need"}),"\n",(0,i.jsx)(t.p,{children:"Automotive systems engineering operates under heavy regulatory weight \u2014 ISO 26262 for functional safety, ASPICE for process maturity, and often ISO 21434 for cybersecurity. A single powertrain ECU can carry thousands of interlinked requirements, each needing a traceable path to hazard analysis and verification."}),"\n",(0,i.jsx)(t.p,{children:"ODM IoT hardware projects \u2014 think a connected sensor device, a smart home gateway, or a wearable built by an ODM for a brand customer \u2014 don't carry that same regulatory load. But the underlying engineering problem is structurally identical:"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:["A ",(0,i.jsx)(t.strong,{children:"customer requirement"}),' ("the device must run 12 months on battery") still needs to flow down into ',(0,i.jsx)(t.strong,{children:"system"}),", ",(0,i.jsx)(t.strong,{children:"hardware"}),", and ",(0,i.jsx)(t.strong,{children:"software requirements"}),"."]}),"\n",(0,i.jsxs)(t.li,{children:["Changes still need ",(0,i.jsx)(t.strong,{children:"impact analysis"})," before they're approved."]}),"\n",(0,i.jsxs)(t.li,{children:["Teams still need to know ",(0,i.jsx)(t.strong,{children:"who approved what"}),", especially when a brand customer is signing off on a specification."]}),"\n",(0,i.jsx)(t.li,{children:"Excel and email still silently fail at scale \u2014 just at a smaller scale than automotive."}),"\n"]}),"\n",(0,i.jsxs)(t.p,{children:["The difference is one of ",(0,i.jsx)(t.em,{children:"degree"}),", not ",(0,i.jsx)(t.em,{children:"kind"}),". Automotive needs a heavyweight, standards-certified ALM platform because the regulatory and safety stakes demand it. ODM IoT teams need the same discipline \u2014 hierarchy, traceability, approvals \u2014 without the certification overhead, integration complexity, or price tag that comes with automotive-grade tooling. That mismatch is exactly where a lot of ODM hardware teams get stuck: too complex for spreadsheets, but automotive ALM platforms are overkill for their scale and budget."]}),"\n",(0,i.jsx)(t.h2,{id:"tool-overview-codebeamer",children:"Tool Overview: Codebeamer"}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.a,{href:"https://codebeamer.com/cb/",children:(0,i.jsx)(t.strong,{children:"Codebeamer"})}),", now part of PTC, is a comprehensive Application Lifecycle Management (ALM) platform rather than a standalone RM tool. That's its defining characteristic: requirements management sits alongside built-in risk management, test management, and change management, all within one connected environment."]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"What stands out:"})}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"End-to-end traceability"})," across requirements, design, risk, and test artifacts, with a traceability browser for drilling into upstream/downstream impact."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Built-in compliance support"})," for standards relevant to automotive (",(0,i.jsx)(t.strong,{children:"ISO 26262"}),"), aerospace (DO-178C), and medical devices (IEC 62304, ISO 13485), which matters a great deal if you're preparing for a functional safety assessment."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Integrations"})," with tools like Jira, GitHub, MATLAB Simulink, and PTC Windchill, so it can sit at the center of a broader engineering toolchain rather than replacing it."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Configurable, no-code workflows"}),", letting teams tailor approval and review processes without custom development."]}),"\n"]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Where it fits:"})," Codebeamer is built for mid-to-large engineering organizations working on complex, safety-critical, or heavily regulated products \u2014 exactly the profile of most automotive OEM and Tier 1 programs. The tradeoff is that this depth comes with real implementation and licensing overhead, which is difficult to justify for a small ODM hardware team shipping a connected sensor."]}),"\n",(0,i.jsx)(t.h2,{id:"tool-overview-reqview",children:"Tool Overview: ReqView"}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.a,{href:"https://www.reqview.com/",children:(0,i.jsx)(t.strong,{children:"ReqView"})})," takes a very different design philosophy. It's a lightweight, desktop-first requirements management tool, built specifically around structured requirement capture and traceability \u2014 without trying to be a full ALM suite."]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"What stands out:"})}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Fast setup, low overhead."})," Teams routinely describe it as easy to deploy and maintain, without the IT footprint of a large ALM platform."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Structured, tabular requirement capture"}),", close to how engineers already think in spreadsheets \u2014 but with proper attributes, discussion threads, and traceability links instead of static cells."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Traceability and impact analysis"}),", including a traceability matrix and side-by-side version comparison, plus built-in FMEA-style risk management."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Git/SVN-based version control"}),", which appeals to engineering teams that already live in a version-controlled workflow rather than a database-backed web platform."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Standards alignment"}),", including templates based on ISO/IEC/IEEE 29148, and use across medical, aerospace, and automotive customers."]}),"\n"]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Where it fits:"})," ReqView is a strong choice for small-to-mid teams that need genuine traceability and structured requirements without committing to a heavyweight ALM platform. It's noticeably closer to the ODM IoT profile than Codebeamer \u2014 but it's still a general-purpose RM tool, not one built around the specific customer \u2192 stakeholder \u2192 system \u2192 hardware \u2192 software hierarchy that ODM hardware programs actually work in."]}),"\n",(0,i.jsx)(t.h2,{id:"the-gap-in-the-middle--and-why-im-building-odm-trace",children:"The Gap in the Middle \u2014 and Why I'm Building ODM Trace"}),"\n",(0,i.jsx)(t.p,{children:"Here's the pattern I kept running into: automotive-grade tools like Codebeamer are powerful but heavy, built for organizations with dedicated ALM administrators and compliance teams. General-purpose lightweight tools like ReqView close some of that gap, but they're still not shaped around the specific workflow an ODM IoT hardware team lives in \u2014 where a brand customer hands you a spec, and you need to trace it cleanly down through system, hardware, and software requirements, with the right person approving each stage."}),"\n",(0,i.jsxs)(t.p,{children:["That's the gap I'm building ",(0,i.jsx)(t.a,{href:"https://odmtrace.com",children:(0,i.jsx)(t.strong,{children:"ODM Trace"})})," to fill."]}),"\n",(0,i.jsxs)(t.p,{children:["ODM Trace is a simple requirement management tool built specifically for ODM IoT hardware teams, structured around a five-level hierarchy \u2014 ",(0,i.jsx)(t.strong,{children:"Customer \u2192 Stakeholder \u2192 System \u2192 Hardware \u2192 Software"})," \u2014 where every child requirement automatically links back to its parent. A few things I'm deliberately designing it around:"]}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Type-specific approvals"})," \u2014 a Customer Requirement routes to a PM, a Hardware Requirement routes to a HW Lead, and so on, with mandatory comments on rejection so nothing gets silently bounced."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Excel import, done right"})," \u2014 because ODM teams ",(0,i.jsx)(t.em,{children:"will"})," keep using spreadsheets for first drafts, so the tool needs to meet them there, catching duplicates and missing fields on the way in rather than pretending spreadsheets don't exist."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"A home for MBSE artifacts without forcing MBSE tooling on everyone"})," \u2014 deep design work still happens in Cameo, Rhapsody, or similar tools, but the exported PDFs, Word docs, and Excel outputs get versioned and linked back to the requirements they satisfy."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Dashboards built for both managers and engineers"})," \u2014 open requests, approval rates, cycle time, and a live traceability matrix, filtered to what each role actually needs."]}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"The goal isn't to compete with Codebeamer on automotive-grade compliance certification, or with ReqView on general-purpose flexibility. It's to give ODM IoT hardware teams the traceability discipline that automotive programs take for granted, sized correctly for teams that don't have \u2014 and don't need \u2014 a full ALM deployment. ODM Trace is currently in early development (Phase 1), and I'll be sharing progress here on MBSE Explained as it moves forward."}),"\n",(0,i.jsx)(t.h2,{id:"choosing-the-right-tool-for-where-you-are",children:"Choosing the Right Tool for Where You Are"}),"\n",(0,i.jsxs)(t.p,{children:["If you're running a safety-critical automotive program with ISO 26262 obligations and a multi-disciplinary engineering org, a platform like ",(0,i.jsx)(t.strong,{children:"Codebeamer"})," is probably worth its complexity. If you're a small-to-mid team that needs real traceability without a heavyweight rollout, ",(0,i.jsx)(t.strong,{children:"ReqView"}),' is a genuinely strong fit. And if you\'re an ODM IoT hardware team caught between "spreadsheets are breaking down" and "we don\'t need automotive-grade ALM," that\'s precisely the space ',(0,i.jsx)(t.strong,{children:"ODM Trace"})," is being built for."]}),"\n",(0,i.jsx)(t.p,{children:"Wherever your project sits on that spectrum, the underlying lesson doesn't change: requirements that aren't traceable aren't really managed \u2014 they're just recorded, and hoping nobody asks hard questions later."}),"\n",(0,i.jsx)(t.p,{children:"What's your experience \u2014 are you managing requirements in a dedicated tool, or still wrestling with spreadsheets? Share your thoughts below! As always, MBSE Explained is here to keep simplifying systems for smarter EVs \u2014 and, increasingly, smarter connected hardware too."})]})}function c(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(h,{...e})}):h(e)}},2587:(e,t,n)=>{n.d(t,{A:()=>a});const a=n.p+"assets/images/image1-417af60cbf848d73f3231fd4d496a41a.png"},3068:e=>{e.exports=JSON.parse('{"permalink":"/blog/requirement-management-tool-automotive-iot","source":"@site/blog/2026-07-07-RequirementTools/index.md","title":"Requirement Management Tool - Why Automotive and IoT Teams Can\'t Afford to Skip One","description":"Discover why a requirement management tool is critical for automotive and ODM IoT teams, the failures it prevents, and an overview of Codebeamer, ReqView, and ODM Trace.","date":"2026-07-07T00:00:00.000Z","tags":[{"inline":true,"label":"MBSE","permalink":"/blog/tags/mbse"},{"inline":true,"label":"automotive","permalink":"/blog/tags/automotive"},{"inline":true,"label":"EV","permalink":"/blog/tags/ev"},{"inline":true,"label":"systems engineering","permalink":"/blog/tags/systems-engineering"},{"inline":true,"label":"requirements management","permalink":"/blog/tags/requirements-management"}],"readingTime":9.09,"hasTruncateMarker":true,"authors":[{"name":"Blagoje Mrkic","title":"Model based Systems Architect","url":"https://blnlabs.com","page":{"permalink":"/blog/authors/all-blagoje-mrkic-articles"},"socials":{"x":"https://x.com/BlagojeMrkic","linkedin":"https://www.linkedin.com/in/blagoje-mrkic-54a385106/","github":"https://github.com/blagojemrkic","newsletter":"https://blnlabs.com"},"imageURL":"https://github.com/blagojemrkic.png","key":"blagoje"}],"frontMatter":{"title":"Requirement Management Tool - Why Automotive and IoT Teams Can\'t Afford to Skip One","description":"Discover why a requirement management tool is critical for automotive and ODM IoT teams, the failures it prevents, and an overview of Codebeamer, ReqView, and ODM Trace.","slug":"requirement-management-tool-automotive-iot","authors":["blagoje"],"tags":["MBSE","automotive","EV","systems engineering","requirements management"],"image":"./image1.png"},"unlisted":false,"nextItem":{"title":"Open Source MBSE Tools for Automotive Engineering: A Practical Guide","permalink":"/blog/open-source-mbse-tools-automotive"}}')},8453:(e,t,n)=>{n.d(t,{R:()=>s,x:()=>o});var a=n(6540);const i={},r=a.createContext(i);function s(e){const t=a.useContext(r);return a.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),a.createElement(r.Provider,{value:t},e.children)}},9652:(e,t,n)=>{n.d(t,{A:()=>a});const a=n.p+"assets/images/image1-417af60cbf848d73f3231fd4d496a41a.png"}}]);